import { translate } from '@utility/i18n.js';

//是否显示主题编辑器
const showThemeEditor = import.meta.env.VITE_SHOW_THEME_EDITOR == 'true';

const thisTheme = ref({});
const thisThemeOverrides = ref({});

const totalLan = ref(zhCN); //全局语言
const totalLanDate = ref(dateZhCN); //全局语言日期格式

onMounted(() => {
    window.addEventListener('lanChange', (e) => {
        lanChanged(e.newValue);
    });
    window.addEventListener('themeChange', (e) => {
        themeChanged(e.newValue);
    });
    window.addEventListener('storage', (e) => {
        if (e.key == 'lan') {
            lanChanged(e.newValue);
        } else if (e.key == 'theme') {
            themeChanged(e.newValue);
        }
    });

    let initLan = window.localStorage.getItem('lan') || 'zh';
    lanChanged(initLan);
    translate.locale.value = initLan;

    //处理主题
    let initTheme = window.localStorage.getItem('theme') || 'TPThemeLight';
    themeChanged(initTheme);
});

//语言变化
function lanChanged(inLan) {
    if (inLan == 'zh') {
        totalLan.value = zhCN; //全局语言
        totalLanDate.value = dateZhCN; //全局语言日期格式
    } else {
        totalLan.value = null; //全局语言
        totalLanDate.value = null; //全局语言日期格式
    }
}

//主题变化
function themeChanged(inTheme) {
    const html = document.querySelector(':root');
    document.body.className = '';
    html.className = '';

    if (inTheme == 'TPThemeDark') {
        thisTheme.value = darkTheme;
        let tempTheme = UnionObj(TPThemeStyle, TPThemeColorDark);
        thisThemeOverrides.value = tempTheme;
        html.className = 'dark';
    } else if (inTheme == 'TPThemeLight') {
        thisTheme.value = {};
        let tempTheme = UnionObj(TPThemeStyle, TPThemeColorLight);
        thisThemeOverrides.value = tempTheme;
        html.className = 'light';
    }

    // if (inTheme == 'NewThemeDark') {
