    //     thisThemeOverrides.value = TCDRI2023;
    //     document.body.className = 'tcdri2023';
    // }
}

function UnionObj(obj1, obj2) {
    let keys = arrayUnion(Object.keys(obj1), Object.keys(obj2));
    let res = {};
    for (const key of keys) {
        res[key] = { ...obj1[key], ...obj2[key] };
    }
    return res;
}
</script>
<template>
    <n-config-provider
        :theme="thisTheme"
        :theme-overrides="thisThemeOverrides"
        :locale="totalLan"
        :date-locale="totalLanDate"
    >
        <n-message-provider>
            <Message></Message>
            <n-dialog-provider>
                <Dialog></Dialog>
